            style={{
              top: i * lineHeight,
              height: lineHeight,
              lineHeight: `${lineHeight}px`,
            }}
          >
            {line.text}
          </motion.div>
          ))}
        </div>
      </div>
    </div>
  );
}

03-fluid-container-morph:
"use client";

import React, { useRef, useState, useMemo } from "react";
import { prepare, layout } from "@chenglou/pretext";
import { motion, useSpring } from "motion/react";
import { GripVertical } from "lucide-react";

export function FluidContainerMorph({
  text = "This is your last chance. After this, there is no turning back. You take the blue pill - the story ends, you wake up in your bed and believe whatever you want to believe. You take the red pill - you stay in Wonderland and I show you how deep the rabbit-hole goes.",
  font = "16px system-ui, -apple-system, sans-serif",
  lineHeight = 28,
}) {
  const [width, setWidth] = useState(400);
  const containerRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);

  // Measure once
  const prepared = useMemo(() => {
    if (typeof window === "undefined") return null;
    return prepare(text, font);
  }, [text, font]);

  // Fast math! layout() doesn't touch the DOM
  const textLayout = useMemo(() => {
    if (!prepared) return { height: lineHeight, lineCount: 1 };
    return layout(prepared, width, lineHeight);
  }, [prepared, width, lineHeight]);

  // Animate the container morph
  // We don't even need a React state to hold the 'spring height', we just let Motion handle it via the 'animate' prop.
  // Actually, spring interpolation is smoother if width is also animated. 
  // Let's use framer-motion's animate prop directly for smooth layout.

  const handlePointerDown = (e: React.PointerEvent) => {
    isDragging.current = true;
    e.currentTarget.setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const newWidth = Math.max(200, Math.min(600, e.clientX - rect.left));
    setWidth(newWidth);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    isDragging.current = false;
    e.currentTarget.releasePointerCapture(e.pointerId);
  };

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-zinc-50/50 dark:bg-zinc-900/50 border-0 rounded-xl overflow-hidden min-h-[400px]">
      <motion.div
        ref={containerRef}
        animate={{
          width,
          height: textLayout.height + 64, // p-8 top/bottom = 64px
        }}
        transition={{
          type: "spring",
          stiffness: 400,
          damping: 30,
        }}
        className="relative bg-white dark:bg-black text-slate-900 dark:text-slate-100shadow-lg border rounded-2xl flex"
      >
        <div 
          className="p-8 pointer-events-none select-none overflow-hidden flex-1 text-slate-700 dark:text-slate-300 antialiased"
          style={{ 
            fontFamily: "system-ui, -apple-system, sans-serif", 
            fontSize: 16, 
            lineHeight: `${lineHeight}px` 
          }}
        >
          {text}
        </div>

        {/* Drag Handle */}
        <div
          className="w-12 h-full flex items-center justify-center cursor-ew-resize border-l border-slate-200 dark:border-slate-800 hover:bg-slate-100 dark:hover:bg-slate-900 transition-colors touch-none bg-slate-50 dark:bg-zinc-900/50"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
          onPointerCancel={handlePointerUp}
        >
          <GripVertical className="text-muted-foreground w-4 h-4" />
        </div>
      </motion.div>
    </div>
  );
}

04-word-gravity:
"use client";

import React, { useEffect, useRef, useState, useMemo } from "react";
import { prepareWithSegments, layoutWithLines } from "@chenglou/pretext";
import { motion, useAnimation } from "motion/react";

export function WordGravity({
  text = "I've seen things you people wouldn't believe. Attack ships on fire off the shoulder of Orion. I watched C-beams glitter in the dark near the Tannhäuser Gate. All those moments will be lost in time, like tears in rain. Time to die.",
  font = "16px system-ui, -apple-system, sans-serif",
  lineHeight = 28,
}) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [width, setWidth] = useState(600);
  const [isPlaying, setIsPlaying] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      setWidth(entries[0].contentRect.width);
    });
    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  const prepared = useMemo(() => {
    if (typeof window === "undefined") return null;
    return prepareWithSegments(text, font);
  }, [text, font]);
  const { lines, height } = useMemo(() => {
    if (!prepared || !width) return { lines: [], height: 0 };
    return layoutWithLines(prepared, width, lineHeight);
  }, [prepared, width, lineHeight]);

  // Build the array of word instances with their exact X,Y layout metrics
  const words = useMemo(() => {
    const list: { id: string; text: string; x: number; y: number; width: number }[] = [];
    if (!lines || lines.length === 0) return list;

    lines.forEach((line, lineIndex) => {
      let currentX = 0;
      // Pretext's PreparedTextWithSegments has internal properties: .segments and .widths
      // Since it's opaque in TS but exposed in JS, we can typecast.
      const raw = prepared as any;
      const widths = raw.widths as number[];
      const segments = raw.segments as string[];

      const startIdx = line.start.segmentIndex;
      // line.end is exclusive, but if graphemeIndex > 0, it means it broke inside a word.
      // For simplicity in WordGravity, assuming words aren't breaking inside (standard words).
      const endIdx = line.end.segmentIndex + (line.end.graphemeIndex > 0 ? 1 : 0);

      for (let i = startIdx; i < endIdx && i < segments.length; i++) {
        const segText = segments[i];
        const segWidth = widths[i];

        // We only animate actual words, not pure whitespace segments.
        if (segText.trim().length > 0) {
          list.push({
            id: `${lineIndex}-${i}`,
            text: segText,
            x: currentX,
            y: lineIndex * lineHeight,
            width: segWidth,
          });
        }
        currentX += segWidth;
      }
    });
    return list;
  }, [prepared, lines, lineHeight]);

  // Replay on hover
  const [playTrigger, setPlayTrigger] = useState(0);

  return (
    <div
      onMouseEnter={() => setPlayTrigger(prev => prev + 1)}
      className="relative w-full bg-white dark:bg-black p-8 cursor-pointer overflow-hidden min-h-[400px] flex flex-col items-center justify-center"
    >
      <div className="absolute top-8 left-8 text-xs font-medium text-slate-500 uppercase tracking-widest flex items-center gap-2">
        <span className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />
        Hover to Trigger Gravity
      </div>

      <div ref={containerRef} className="relative w-full max-w-2xl px-4">
        <div key={playTrigger} className="relative w-full" style={{ height }}>
          {lines.map((line, lineIndex) => (
          <div
            key={lineIndex}
            className="absolute left-0 right-0 whitespace-nowrap text-center text-slate-900 dark:text-slate-100"
            style={{
              top: lineIndex * lineHeight,
              height: lineHeight,
              lineHeight: `${lineHeight}px`,
            }}
          >
            {line.text.split(/(\s+)/).map((segment, j) => {
              const isSpace = segment.trim().length === 0;
              return (
                <motion.span
                  key={j}
                  initial={{
                    y: !isSpace ? -300 - Math.random() * 200 : 0,
                    opacity: !isSpace ? 0 : 1,
                    rotate: !isSpace ? Math.random() * 60 - 30 : 0,
                  }}
                  animate={{ y: 0, opacity: 1, rotate: 0 }}
                  transition={{
                    type: "spring",
                    stiffness: 150 + Math.random() * 50,
                    damping: 12 + Math.random() * 5,
                    delay: !isSpace ? Math.random() * 0.2 : 0,
                  }}
                  className="inline-block"
                  style={{ whiteSpace: "pre" }}
                >
                  {segment}
                </motion.span>
              );
            })}
          </div>
          ))}
        </div>
      </div>
    </div>
  );
}

05-live-typewriter:
"use client";

import React, { useEffect, useRef, useState, useMemo } from "react";
import { prepare, layout } from "@chenglou/pretext";
import { motion } from "motion/react";

export function LiveTypewriter({
  fullText = "I love the smell of napalm in the morning. You know, one time we had a hill bombed, for 12 hours. When it was all over, I walked up. We didn't find one of 'em, not one stinkin' dink body. The smell, you know that gasoline smell? The whole hill. Smelled like... victory.",
  font = "16px system-ui, -apple-system, sans-serif",
  lineHeight = 28,
}) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [width, setWidth] = useState(600);
  const [charCount, setCharCount] = useState(0);

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      setWidth(entries[0].contentRect.width);
    });
    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    setCharCount(0); // reset when fullText changes
    const timer = setInterval(() => {
      setCharCount((c) => Math.min(c + 1, fullText.length)); // type 1 char per tick
    }, 40);
    return () => clearInterval(timer);
  }, [fullText]);

  // We substring the requested text
  const currentText = fullText.slice(0, charCount);

  // Re-measure height continuously as characters accumulate
  const prepared = useMemo(() => {
    if (typeof window === "undefined") return null;
    return prepare(currentText, font);
  }, [currentText, font]);
  const textLayout = useMemo(() => {
    if (!prepared || !width) return { height: lineHeight, lineCount: 1 };
    return layout(prepared, width, lineHeight);
  }, [prepared, width, lineHeight]);

  return (
    <div
      onMouseEnter={() => setCharCount(0)}
      className="relative w-full bg-white dark:bg-black p-8 min-h-[400px] flex flex-col items-center justify-center cursor-pointer"
    >
      <div className="absolute top-8 left-8 text-xs font-medium text-slate-500 uppercase tracking-widest flex items-center gap-2">
        <span className="w-2 h-2 rounded-full bg-primary animate-pulse" />
        Hover to restart
      </div>

      {/* We animate the container bounding height */}
      <motion.div
        ref={containerRef}
        animate={{ height: textLayout.height }}
        transition={{ type: "spring", stiffness: 400, damping: 30 }}
        className="relative w-full max-w-lg overflow-hidden border-l-2 border-primary pl-4 text-slate-900 dark:text-slate-100"
        style={{
          fontFamily: "system-ui, -apple-system, sans-serif",
          fontSize: 16,
          lineHeight: `${lineHeight}px`,
        }}
      >
        <span>{currentText}</span>
        <motion.span
          animate={{ opacity: [1, 0] }}
          transition={{ repeat: Infinity, duration: 0.8 }}
          className="inline-block w-2 h-4 bg-primary ml-1 align-baseline translate-y-0.5"
        />
      </motion.div>
    </div>
  );
}

06-dragon-follower:
"use client";

import React, { useEffect, useRef, useState, useMemo } from "react";
import { prepareWithSegments, layoutWithLines } from "@chenglou/pretext";
import { motion, useSpring } from "motion/react";

/**
 * 06 — Dragon Follower
 * Text lines smoothly arc toward the cursor position like a dragon's tail following its head.
 * Each line gets a decreasing rotation/translation offset based on distance from cursor Y.
 */
export function DragonFollower({
  text = "As far back as I can remember, I always wanted to be a gangster. To me, being a gangster was better than being President of the United States. Even before I first wandered into the cabstand for an after-school job, I knew I wanted to be a part of them.",
  font = "16px system-ui, -apple-system, sans-serif",
  lineHeight = 28,
}) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [width, setWidth] = useState(600);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  const smoothX = useSpring(0, { stiffness: 150, damping: 20 });
  const smoothY = useSpring(0, { stiffness: 150, damping: 20 });

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      setWidth(entries[0].contentRect.width);
    });
    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setMousePos({ x, y });
    smoothX.set(x);
    smoothY.set(y);
  };

  const handleMouseLeave = () => {
    setMousePos({ x: width / 2, y: 0 });
    smoothX.set(width / 2);
    smoothY.set(0);
  };

  const prepared = useMemo(() => {
    if (typeof window === "undefined") return null;
    return prepareWithSegments(text, font);
  }, [text, font]);

  const { lines, height } = useMemo(() => {
    if (!prepared || !width) return { lines: [], height: 0 };
    return layoutWithLines(prepared, width, lineHeight);
  }, [prepared, width, lineHeight]);

  return (
    <div
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      className="relative w-full bg-white dark:bg-black p-8 cursor-pointer overflow-hidden min-h-[400px] flex flex-col"
    >
      <div className="text-xs font-medium text-slate-500 uppercase tracking-widest flex items-center gap-2 relative z-10 w-full">
        <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
        Move cursor across text
      </div>

      <div className="flex-1 w-full flex items-center justify-center">
        <div ref={containerRef} className="relative w-full max-w-2xl px-4" style={{ height }}>
          {lines.map((line, i) => {
            const lineCenterY = i * lineHeight + lineHeight / 2;
            const dy = mousePos.y - lineCenterY;

            // Stronger influence closer to the cursor Y
            const influence = Math.max(0, 1 - Math.abs(dy) / 200);

            // Shift X towards cursor, with easing based on Y-distance
            const targetX = mousePos.x - width / 2; // relative to center
            const offsetX = targetX * Math.pow(influence, 1.5) * 0.9;
            const rotation = targetX * influence * 0.04;
            const scale = 1 + influence * 0.05;

            return (
              <motion.div
                key={i}
                animate={{
                  x: offsetX,
                  rotate: rotation,
                  scale,
                }}
                transition={{
                  type: "spring",
                  stiffness: 250,
                  damping: 20,
                  mass: 0.5 + Math.abs(dy) * 0.002, // lines further away lag a bit more
                }}
                className="absolute left-0 right-0 whitespace-pre text-center text-slate-900 dark:text-slate-100"
                style={{
                  top: i * lineHeight,
                  height: lineHeight,
                  lineHeight: `${lineHeight}px`,
                  transformOrigin: "center center",
                }}
              >
                {line.text}
              </motion.div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

07-paragraph-breath:
"use client";

import React, { useEffect, useRef, useState, useMemo } from "react";
import { prepare, layout, prepareWithSegments, layoutWithLines } from "@chenglou/pretext";
import { motion, useMotionValue, animate } from "motion/react";

/**
 * 07 — Paragraph Breath
 * The container's width subtly pulsates in and out on a loop.
 * Pretext recalculates the layout each tick, and Motion smoothly
 * animates the height change, creating a "breathing" paragraph.
 */
export function ParagraphBreath({
  text = "Introduce a little anarchy. Upset the established order, and everything becomes chaos. I'm an agent of chaos. Oh, and you know the thing about chaos? It's fair. The joker's card is wild.",
  font = "16px system-ui, -apple-system, sans-serif",
  lineHeight = 28,
  minWidth = 280,
  maxWidth = 520,
}) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [parentWidth, setParentWidth] = useState(600);
  const breathWidth = useMotionValue(maxWidth);
  const [currentWidth, setCurrentWidth] = useState(maxWidth);

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      setParentWidth(entries[0].contentRect.width);
    });
    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  // Breathing animation loop
  useEffect(() => {
    const effectiveMax = Math.min(maxWidth, parentWidth - 64);
    const effectiveMin = Math.min(minWidth, effectiveMax - 40);

    const controls = animate(breathWidth, [effectiveMax, effectiveMin, effectiveMax], {
      duration: 6,
      repeat: Infinity,
      ease: "easeInOut",
    });

    const unsub = breathWidth.on("change", (v) => setCurrentWidth(v));
    return () => {
      controls.stop();
      unsub();
    };
  }, [breathWidth, minWidth, maxWidth, parentWidth]);

  const prepared = useMemo(() => {
    if (typeof window === "undefined") return null;
    return prepare(text, font);
  }, [text, font]);
  const preparedWithSegs = useMemo(() => {
    if (typeof window === "undefined") return null;
    return prepareWithSegments(text, font);
  }, [text, font]);

  const textLayout = useMemo(() => {
    if (!prepared) return { height: 0, lineCount: 0 };
    return layout(prepared, currentWidth, lineHeight);
  }, [prepared, currentWidth, lineHeight]);

  const { lines } = useMemo(() => {
    if (!preparedWithSegs || currentWidth === 0) return { lines: [], height: 0 };
    return layoutWithLines(preparedWithSegs, currentWidth, lineHeight);
  }, [preparedWithSegs, currentWidth, lineHeight]);

  return (
    <div
      ref={containerRef}
      className="relative w-full bg-white dark:bg-black p-8 flex flex-col items-center justify-center min-h-[400px] overflow-hidden"
    >
      <motion.div
        animate={{
          width: currentWidth,
          height: textLayout.height + 48,
        }}
        transition={{ type: "spring", stiffness: 300, damping: 30 }}
        className="relative bg-gradient-to-br from-slate-50 to-slate-100 dark:from-zinc-900 dark:to-zinc-950 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl overflow-hidden max-w-full"
      >
        <div className="p-6" style={{ fontFamily: "system-ui, -apple-system, sans-serif", fontSize: 16, lineHeight: `${lineHeight}px` }}>
          <div className="relative" style={{ height: textLayout.height }}>
            {lines.map((line, i) => (
              <div
                key={i}
                className="absolute left-0 right-0 whitespace-pre text-center text-slate-700 dark:text-slate-300 "
                style={{
                  top: i * lineHeight,
                  height: lineHeight,
                  lineHeight: `${lineHeight}px`,
                }}
              >
                {line.text}
              </div>
            ))}
          </div>
        </div>
      </motion.div>
    </div>
  );
}

